import json
import urllib.request
import urllib.error
from urllib.parse import urlparse

def fetch_and_display_url_content(url: str, timeout: int = 10, max_bytes: int = 65536):
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https") or not parsed.netloc:
        raise ValueError("Invalid URL. Only http and https URLs are allowed.")

    req = urllib.request.Request(
        url,
        headers={
            "User-Agent": "WebhookIntegrationFetcher/1.0",
            "Accept": "*/*",
        },
        method="GET",
    )

    with urllib.request.urlopen(req, timeout=timeout) as response:
        content_type = response.headers.get_content_type()
        charset = response.headers.get_content_charset() or "utf-8"
        data = response.read(max_bytes)

    if content_type == "application/json":
        try:
            content = json.loads(data.decode(charset, errors="replace"))
            print(json.dumps(content, indent=2, ensure_ascii=False))
        except Exception:
            print(data.decode(charset, errors="replace"))
    else:
        print(data.decode(charset, errors="replace"))

def fetch_webhook_payload(payload: dict):
    url = payload.get("url")
    if not url:
        raise ValueError("Payload must include a 'url' field.")
    fetch_and_display_url_content(url)

if __name__ == "__main__":
    import sys
    if len(sys.argv) > 1:
        fetch_and_display_url_content(sys.argv[1])
    else:
        user_url = input("Enter URL: ").strip()
        fetch_and_display_url_content(user_url)